/**
 * Flag-gated DPhyp adapter for {@link LmdbCascadesConnectedJoinPlanner}: maps an inner-join island onto the
 * {@link org.eclipse.rdf4j.sail.lmdb.hypergraph} optimizer, which searches all connected join trees — bushy included —
 * instead of only connected left-deep prefixes.
 * <p>
 * Enabled by default; disable with {@code -Drdf4j.optimizer.lmdb.cascades.connectedJoin.dphyp=false}. The v1 scope is
 * deliberately narrow: every factor must be a plain {@link StatementPattern} with at least one runtime variable, and
 * the island must have 3..maxFactors factors whose shared-variable graph is connected. Anything else returns empty and
 * the caller falls through to the existing left-deep planner.
 * <p>
 * Estimates reuse the same {@link JoinFactorCostModel} probes as the left-deep planner: base cardinalities come from
 * unbound-context probes, per-edge join selectivities are derived from pairwise conditional probes (selectivity =
 * rows(j joined onto i) / (rows(i) × rows(j))), and nested-loop lookup costs from bound-context probes. Row estimates
 * inside the search are canonical per node set, so every join tree of the same factors gets the same cardinality.
 */
final class LmdbHypergraphJoinPlanner {

	static final String DPHYP_PROPERTY = "rdf4j.optimizer.lmdb.cascades.connectedJoin.dphyp";
	static final String DPHYP_MAX_FACTORS_PROPERTY = "rdf4j.optimizer.lmdb.cascades.connectedJoin.dphyp.maxFactors";
	static final String ESTIMATE_SOURCE = "lmdb-cascades-dphyp";
	static final String ALGORITHM = "dphyp-bushy";
	static final String PLANNER_ALGORITHM_METRIC_VALUE = "DPHYP_BUSHY";
	static final String DPHYP_RANK_COST_METRIC = "optimizer.dphypRankCost";
	private static final int MIN_FACTORS = 3;
	private static final int DEFAULT_MAX_FACTORS = 14;
	private static final long PAIR_BUDGET = 100_000L;
	private static final double MIN_ROWS = 1e-9d;

	private LmdbHypergraphJoinPlanner() {
	}

	static boolean enabled() {
		return Boolean.parseBoolean(System.getProperty(DPHYP_PROPERTY, "true"));
	}

	private static int maxFactors() {
		String value = System.getProperty(DPHYP_MAX_FACTORS_PROPERTY);
		if (value == null || value.isBlank()) {
			return DEFAULT_MAX_FACTORS;
		}
		try {
			// 20 matches the existing planner's exact-DP limit; the pair budget bounds dense graphs below that.
			return Math.max(MIN_FACTORS, Math.min(20, Integer.parseInt(value.trim())));
		} catch (NumberFormatException e) {
			return DEFAULT_MAX_FACTORS;
		}
	}

	static Optional<LmdbCascadesConnectedJoinPlanner.Plan> tryPlan(List<TupleExpr> factors,
			Set<String> initialBoundVars, JoinFactorCostModel costModel, EvaluationStatistics fallbackStatistics,
			EstimationTier estimationTier, LmdbCascadesConnectedJoinPlanner.Trace trace) {
		EstimationTier tier = estimationTier == null ? EstimationTier.STANDARD : estimationTier;
		int factorCount = factors.size();
		if (factorCount < MIN_FACTORS || factorCount > maxFactors()) {
			traceDecline(trace, "factor-count=" + factorCount);
			return Optional.empty();
		}
		Set<String> initial = LmdbJoinPlanSupport.plannerBindingNames(initialBoundVars);
		List<Set<String>> factorJoinVars = new ArrayList<>(factorCount);
		for (TupleExpr factor : factors) {
			if (!(factor instanceof StatementPattern)) {
				traceDecline(trace, "non-statement-pattern factor " + factor.getSignature());
				return Optional.empty();
			}
			Set<String> vars = new HashSet<>(LmdbJoinPlanSupport.runtimeBindingNames(factor));
			vars.removeAll(initial);
			if (vars.isEmpty()) {
				traceDecline(trace, "zero-runtime-var factor");
				return Optional.empty();
			}
			factorJoinVars.add(vars);
		}

		PlanHypergraph planGraph = new PlanHypergraph();
		LmdbCascadesConnectedJoinPlanner.Step[] seedSteps = new LmdbCascadesConnectedJoinPlanner.Step[factorCount];
		double[] baseRows = new double[factorCount];
		for (int i = 0; i < factorCount; i++) {
			LmdbCascadesConnectedJoinPlanner.Step step = LmdbCascadesConnectedJoinPlanner.estimateStep(factors, i,
					initial, 0.0d, false, List.of(), costModel, fallbackStatistics, tier);
			if (step == null) {
				traceDecline(trace, "no-seed-estimate f" + i);
				return Optional.empty();
			}
			seedSteps[i] = step;
			baseRows[i] = Math.max(step.outputRows(), MIN_ROWS);
			planGraph.addNode("f" + i, baseRows[i]);
		}
		for (int i = 0; i < factorCount; i++) {
			for (int j = i + 1; j < factorCount; j++) {
				Set<String> shared = new TreeSet<>(factorJoinVars.get(i));
				shared.retainAll(factorJoinVars.get(j));
				if (shared.isEmpty()) {
					continue;
				}
				double selectivity = edgeSelectivity(factors, i, j, initial, factorJoinVars, baseRows, costModel,
						fallbackStatistics, tier);
				planGraph.addJoinEdge(NodeSets.bit(i), NodeSets.bit(j), selectivity, String.join(",", shared));
			}
		}

		ProbingCostModel adapterCostModel = new ProbingCostModel(factors, factorJoinVars, initial, seedSteps, costModel,
				fallbackStatistics, tier);
		Optional<JoinPlan> best = HypergraphOptimizer.bestPlan(planGraph, adapterCostModel, PAIR_BUDGET);
		if (best.isEmpty()) {
			traceDecline(trace, "no-full-plan (disconnected island or pair budget exhausted)");
			return Optional.empty();
		}
		JoinPlan winner = best.get();
		if (trace.enabled()) {
			trace.add("dphyp winner " + winner.describe(planGraph::nodeName) + " rows="
					+ winner.rows() + " rankCost=" + winner.cost());
		}
		return Optional.of(toPlan(winner, factors, seedSteps, factorCount, adapterCostModel));
	}

	/**
	 * Derives the join selectivity of the factor pair from conditional probes: estimating factor {@code j} with factor
	 * {@code i}'s variables bound and {@code rows(i)} prefix rows yields the joined row count, so selectivity = output
	 * / (rows(i) × rows(j)). In theory both probe directions describe the same joined cardinality; real estimators can
	 * disagree, so both directions are probed and combined with a geometric mean (the natural average for
	 * multiplicative quantities). Falls back to 1.0 (no reduction) when both probes fail; the clamp into (0, 1] happens
	 * in {@link PlanHypergraph#addPredicate}.
	 */
	private static double edgeSelectivity(List<TupleExpr> factors, int i, int j, Set<String> initial,
			List<Set<String>> factorJoinVars, double[] baseRows, JoinFactorCostModel costModel,
			EvaluationStatistics fallbackStatistics, EstimationTier tier) {
		double forward = directionalSelectivity(factors, i, j, initial, factorJoinVars, baseRows, costModel,
				fallbackStatistics, tier);
		double backward = directionalSelectivity(factors, j, i, initial, factorJoinVars, baseRows, costModel,
				fallbackStatistics, tier);
		if (Double.isNaN(forward)) {
			return Double.isNaN(backward) ? 1.0d : backward;
		}
		if (Double.isNaN(backward)) {
			return forward;
		}
		return Math.sqrt(forward * backward);
	}

	private static double directionalSelectivity(List<TupleExpr> factors, int boundFactor, int probedFactor,
			Set<String> initial, List<Set<String>> factorJoinVars, double[] baseRows, JoinFactorCostModel costModel,
			EvaluationStatistics fallbackStatistics, EstimationTier tier) {
		Set<String> boundVars = new HashSet<>(initial);
		boundVars.addAll(factorJoinVars.get(boundFactor));
		LmdbCascadesConnectedJoinPlanner.Step conditional = LmdbCascadesConnectedJoinPlanner.estimateStep(factors,
				probedFactor, boundVars, baseRows[boundFactor], true, List.of(factors.get(boundFactor)), costModel,
				fallbackStatistics, tier);
		if (conditional == null) {
			return Double.NaN;
		}
		double joined = conditional.outputRows();
		if (!Double.isFinite(joined) || joined < 0.0d) {
			return Double.NaN;
		}
		return joined / (baseRows[boundFactor] * baseRows[probedFactor]);
	}

	/**
	 * Cost callbacks backed by the LMDB estimator: scans cost their probe's work rows; nested-loop lookups probe the
	 * inner factor with the outer side's variables bound (cached per (node, bound node set) — the outer row count is
	 * canonical per node set, so the key is complete).
	 */
	private static final class ProbingCostModel implements CostModel {
		private final List<TupleExpr> factors;
		private final List<Set<String>> factorJoinVars;
		private final Set<String> initial;
		private final LmdbCascadesConnectedJoinPlanner.Step[] seedSteps;
		private final JoinFactorCostModel costModel;
		private final EvaluationStatistics fallbackStatistics;
		private final EstimationTier tier;
		private final Map<LookupKey, LookupProbe> lookupProbeCache = new HashMap<>();

		private ProbingCostModel(List<TupleExpr> factors, List<Set<String>> factorJoinVars, Set<String> initial,
				LmdbCascadesConnectedJoinPlanner.Step[] seedSteps, JoinFactorCostModel costModel,
				EvaluationStatistics fallbackStatistics, EstimationTier tier) {
			this.factors = factors;
			this.factorJoinVars = factorJoinVars;
			this.initial = initial;
			this.seedSteps = seedSteps;
			this.costModel = costModel;
			this.fallbackStatistics = fallbackStatistics;
			this.tier = tier;
		}

		@Override
		public double scanCost(int nodeIdx, double cardinality) {
			return Math.max(seedSteps[nodeIdx].workRows(), MIN_ROWS);
		}

		@Override
		public double hashJoinCost(double probeRows, double buildRows, double outputRows) {
			return 2.0d * buildRows + probeRows + 0.5d * outputRows;
		}

		@Override
		public double nestedLoopLookupCost(int nodeIdx, long boundNodes, double outerRows) {
			return nestedLoopLookupProbe(nodeIdx, boundNodes, outerRows).workRows();
		}

		private LookupProbe nestedLoopLookupProbe(int nodeIdx, long boundNodes, double outerRows) {
			LookupKey key = new LookupKey(nodeIdx, boundNodes, Double.doubleToLongBits(outerRows));
			LookupProbe cached = lookupProbeCache.get(key);
			if (cached != null) {
				return cached;
			}
			Set<String> boundVars = new HashSet<>(initial);
			List<TupleExpr> prefixFactors = new ArrayList<>();
			for (long rest = boundNodes; rest != 0; rest &= rest - 1L) {
				int idx = Long.numberOfTrailingZeros(rest);
				boundVars.addAll(factorJoinVars.get(idx));
				prefixFactors.add(factors.get(idx));
			}
			LmdbCascadesConnectedJoinPlanner.Step step = LmdbCascadesConnectedJoinPlanner.estimateStep(factors,
					nodeIdx, boundVars, Math.max(outerRows, MIN_ROWS), true, prefixFactors, costModel,
					fallbackStatistics, tier);
			LookupProbe probe = step == null
					? new LookupProbe(null, Double.NaN, Double.NaN)
					: new LookupProbe(step, step.outputRows(), Math.max(step.workRows(), MIN_ROWS));
			lookupProbeCache.put(key, probe);
			return probe;
		}
	}

	private record LookupKey(int nodeIdx, long boundNodes, long outerRowsBits) {
	}

	private record LookupProbe(LmdbCascadesConnectedJoinPlanner.Step step, double outputRows, double workRows) {
	}

	private static LmdbCascadesConnectedJoinPlanner.Plan toPlan(JoinPlan winner, List<TupleExpr> factors,
			LmdbCascadesConnectedJoinPlanner.Step[] seedSteps, int factorCount, ProbingCostModel costModel) {
		double rowQErrorMax = 1.0d;
		double workQErrorMax = 1.0d;
		double confidence = 1.0d;
		double evidenceCount = 0.0d;
		for (LmdbCascadesConnectedJoinPlanner.Step step : seedSteps) {
			rowQErrorMax = Math.max(rowQErrorMax, step.rowQErrorMax());
			workQErrorMax = Math.max(workQErrorMax, step.workQErrorMax());
			confidence = Math.min(confidence, step.confidence());
			evidenceCount += step.evidenceCount();
		}
		ExportedPlan exportedPlan = toTupleExpr(winner, factors, seedSteps, costModel);
		double rows = exportedPlan.rows();
		double workRows = exportedPlan.workRows();
		CostVector cost = new CostVector(rows, workRows, 0.0d, 0.0d, 0.0d, rowQErrorMax, rowQErrorMax, workQErrorMax,
				workQErrorMax, Math.max(0.0d, rows * Math.max(rowQErrorMax - 1.0d, 0.0d)), confidence, evidenceCount);
		TupleExpr tupleExpr = exportedPlan.tupleExpr();
		Map<String, String> strings = new LinkedHashMap<>();
		strings.put(TelemetryMetricNames.PLANNER_ID, "lmdb-cascades");
		strings.put(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE, ESTIMATE_SOURCE);
		strings.put(TelemetryMetricNames.PLANNED_ESTIMATE_USAGE,
				TelemetryMetricNames.PLANNED_ESTIMATE_USAGE_ALTERNATIVE_RANKING);
		strings.put(TelemetryMetricNames.PLANNED_CARDINALITY_SHAPE, "scalar");
		strings.put(TelemetryMetricNames.PLANNED_COST_SHAPE, "vector");
		strings.put(TelemetryMetricNames.PLANNER_ALGORITHM, PLANNER_ALGORITHM_METRIC_VALUE);
		strings.put("optimizer.hypergraphPlanner", ALGORITHM);
		Map<String, Double> doubles = new LinkedHashMap<>();
		doubles.put("optimizer.joinIslandFactorCount", (double) factorCount);
		doubles.put(DPHYP_RANK_COST_METRIC, winner.cost());
		doubles.put(TelemetryMetricNames.PLANNED_WORK_ROWS, workRows);
		doubles.put(TelemetryMetricNames.PLANNED_COST_WORK_ROWS, workRows);
		doubles.put(TelemetryMetricNames.PLANNED_COST_FINAL_ROWS, rows);
		doubles.put(TelemetryMetricNames.PLANNED_OBJECTIVE_SCORE, cost.objectiveScore());
		EstimateSnapshot estimate = new EstimateSnapshot("lmdb-cascades", ESTIMATE_SOURCE,
				TelemetryMetricNames.PLANNED_ESTIMATE_USAGE_ALTERNATIVE_RANKING, rows, workRows, cost,
				java.util.Collections.unmodifiableMap(strings), java.util.Collections.unmodifiableMap(doubles));
		return new LmdbCascadesConnectedJoinPlanner.Plan(tupleExpr, cost, estimate, factorCount, ALGORITHM, 0);
	}

	private record ExportedPlan(TupleExpr tupleExpr, double rows, double workRows) {
	}

	private static ExportedPlan toTupleExpr(JoinPlan plan, List<TupleExpr> factors,
			LmdbCascadesConnectedJoinPlanner.Step[] seedSteps, ProbingCostModel costModel) {
		if (plan.kind() == JoinPlan.Kind.SCAN) {
			return scanTupleExpr(plan, factors, seedSteps[plan.scanNode()], plan.rows(),
					seedSteps[plan.scanNode()].workRows(), plan.cost());
		}
		ExportedPlan left = toTupleExpr(plan.left(), factors, seedSteps, costModel);
		ExportedPlan right;
		double rows = plan.rows();
		double workRows;
		String rowRepairReason = null;
		double lookupRows = Double.NaN;
		if (plan.kind() == JoinPlan.Kind.NESTED_LOOP) {
			LookupProbe lookupProbe = costModel.nestedLoopLookupProbe(plan.right().scanNode(), plan.left().nodes(),
					left.rows());
			double lookupWorkRows = finiteNonNegative(lookupProbe.workRows(), MIN_ROWS);
			lookupRows = finiteNonNegative(lookupProbe.outputRows(), Double.NaN);
			if (Double.isFinite(lookupRows)) {
				rows = Math.max(rows, lookupRows);
			}
			TupleExpr rightFactor = factors.get(plan.right().scanNode());
			if (rows > 0.0d && finitePositive(left.rows()) && rows < left.rows()
					&& sharesRuntimeBindings(left.tupleExpr(), rightFactor)) {
				rows = left.rows();
				rowRepairReason = "shared-binding-nested-lookup-floor";
			}
			LmdbCascadesConnectedJoinPlanner.Step rightStep = lookupProbe.step() == null
					? seedSteps[plan.right().scanNode()]
					: lookupProbe.step();
			double rightRows = Double.isFinite(lookupRows) ? lookupRows : plan.right().rows();
			right = scanTupleExpr(plan.right(), factors, rightStep, rightRows, lookupWorkRows,
					lookupWorkRows);
			workRows = left.workRows() + lookupWorkRows;
		} else {
			right = toTupleExpr(plan.right(), factors, seedSteps, costModel);
			workRows = left.workRows() + right.workRows();
		}
		Join join = new Join(left.tupleExpr(), right.tupleExpr());
		copyOmniEvidenceMetrics(join, right.tupleExpr());
		if (join.getStringMetricPlanned(LmdbOmniEvidenceStore.PLANNED_OMNI_EVIDENCE_FINGERPRINT) == null) {
			copyOmniEvidenceMetrics(join, left.tupleExpr());
		}
		join.setStringMetricPlanned(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE, ESTIMATE_SOURCE);
		join.setStringMetricPlanned(TelemetryMetricNames.PLANNER_ALGORITHM, PLANNER_ALGORITHM_METRIC_VALUE);
		join.setDoubleMetricPlanned(TelemetryMetricNames.PLANNED_CARDINALITY_ROWS, rows);
		join.setDoubleMetricPlanned(TelemetryMetricNames.PLANNED_WORK_ROWS, workRows);
		join.setDoubleMetricPlanned(TelemetryMetricNames.PLANNED_COST_WORK_ROWS, workRows);
		join.setDoubleMetricPlanned(DPHYP_RANK_COST_METRIC, plan.cost());
		if (Double.isFinite(lookupRows)) {
			join.setDoubleMetricPlanned("optimizer.dphypNestedLookupRows", lookupRows);
		}
		if (rowRepairReason != null) {
			join.setStringMetricPlanned("optimizer.dphypRowRepair", rowRepairReason);
		}
		if (plan.kind() == JoinPlan.Kind.HASH_JOIN) {
			join.setStringMetricPlanned("optimizer.joinAlgorithmHint", "hash");
		}
		return new ExportedPlan(join, rows, workRows);
	}

	private static void copyOmniEvidenceMetrics(TupleExpr target, TupleExpr source) {
		if (target == null || source == null) {
			return;
		}
		for (Map.Entry<String, String> entry : source.getStringMetricsPlanned().entrySet()) {
			if (entry.getKey().startsWith("plannedOmni")) {
				target.setStringMetricPlanned(entry.getKey(), entry.getValue());
			}
		}
		for (Map.Entry<String, Double> entry : source.getDoubleMetricsPlanned().entrySet()) {
			if (entry.getKey().startsWith("plannedOmni")) {
				target.setDoubleMetricPlanned(entry.getKey(), entry.getValue());
			}
		}
	}

	private static ExportedPlan scanTupleExpr(JoinPlan plan, List<TupleExpr> factors,
			LmdbCascadesConnectedJoinPlanner.Step step, double rows, double workRows, double rankCost) {
		TupleExpr clone = factors.get(plan.scanNode()).clone();
		if (step != null) {
			for (Map.Entry<String, String> entry : step.stringMetrics().entrySet()) {
				clone.setStringMetricPlanned(entry.getKey(), entry.getValue());
			}
			for (Map.Entry<String, Double> entry : step.doubleMetrics().entrySet()) {
				clone.setDoubleMetricPlanned(entry.getKey(), entry.getValue());
			}
		}
		clone.setStringMetricPlanned(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE, ESTIMATE_SOURCE);
		clone.setDoubleMetricPlanned(TelemetryMetricNames.PLANNED_CARDINALITY_ROWS, rows);
		clone.setDoubleMetricPlanned(TelemetryMetricNames.PLANNED_WORK_ROWS, workRows);
		clone.setDoubleMetricPlanned(TelemetryMetricNames.PLANNED_COST_WORK_ROWS, workRows);
		clone.setDoubleMetricPlanned(DPHYP_RANK_COST_METRIC, rankCost);
		return new ExportedPlan(clone, rows, workRows);
	}

	private static double finiteNonNegative(double value, double fallback) {
		return Double.isFinite(value) && value >= 0.0d ? value : fallback;
	}

	private static boolean finitePositive(double value) {
		return Double.isFinite(value) && value > 0.0d;
	}

	private static boolean sharesRuntimeBindings(TupleExpr left, TupleExpr right) {
		Set<String> shared = new HashSet<>(LmdbJoinPlanSupport.runtimeBindingNames(left));
		shared.retainAll(LmdbJoinPlanSupport.runtimeBindingNames(right));
		return !shared.isEmpty();
	}

	private static void traceDecline(LmdbCascadesConnectedJoinPlanner.Trace trace, String reason) {
		if (trace.enabled()) {
			trace.add("dphyp decline " + reason);
		}
	}
}
